}

function ClockIcon() {
  return (
    <svg
      className="w-3 h-3 text-gray-600"
      fill="none"
      stroke="currentColor"
      viewBox="0 0 24 24"
    >
      <circle cx="12" cy="12" r="10" strokeWidth="2" />
